#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
CI MAXN=1e1+5;
struct node
{
	int a,b;
}c[MAXN];
int n,mi=inf,t[MAXN];
bool vis[MAXN];
void f()
{
    int sum=1;
	for(int i=2;i<=n;++i)
    {
        sum+=max(c[t[i]].b,c[t[i-1]].a),sum+=1;
    }
	mi=min(mi,sum);return;
}
void dfs(int x)
{
	if(x>n)
    {
        f();
        return;
    }
	for(int i=1;i<=n;++i)
    {
        if(!vis[i])
        {
            vis[i]=true,t[x]=i;dfs(x+1);vis[i]=false;
        }
    }
    return;
}
int main(void){
	scanf("%d",&n);
	for(int i=1;i<=n;++i)
    {
        scanf("%d",&c[i].a);
    }
	for(int i=1;i<=n;++i)
    {
        scanf("%d",&c[i].b);
    }
	dfs(1);
    printf("%d",mi);
	return false;
}
